-- LANGKAH 1: HAPUS DATA LAMA + IMPORT 210 PRODUK
-- Stok awal: 100 untuk semua (bibit 100ml, botol 100pcs)
-- ═══════════════════════════════════════════════════

-- HAPUS data lama (urutan penting: anak dulu, baru induk)
DELETE FROM transaksi_item WHERE transaksi_id IN (SELECT id FROM transaksi WHERE toko_id = (SELECT id FROM toko LIMIT 1));
DELETE FROM transaksi WHERE toko_id = (SELECT id FROM toko LIMIT 1);
DELETE FROM stok_movement WHERE toko_id = (SELECT id FROM toko LIMIT 1);
DELETE FROM varian WHERE produk_id IN (SELECT id FROM produk WHERE toko_id = (SELECT id FROM toko LIMIT 1));
DELETE FROM produk WHERE toko_id = (SELECT id FROM toko LIMIT 1);

-- INSERT 210 produk (stok = 100)
